INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('pe_charge_entry_glide_dead_when_no_slide', 'updatePeChargeFrame''s enter/glide branch is unreachable dead code for any charge that authors enter_from but no slide_to -- slideAt defaulted to 0, making `ms < slideAt` false for every non-negative ms, so the charge snapped straight to its rest position from frame 0 instead of gliding in over enter_dur_ms', 'MAJOR', 'peter_parker:renderer_primitives', 'FIXED 2026-07-08. field_3d_renderer.ts''s updatePeChargeFrame() computed `var slideAt = (pc.slide_at_ms != null) ? pc.slide_at_ms : 0;` then gated the enter/glide branch on `pc.enter_from && ms < slideAt`. For an entry-only charge (enter_from + enter_at_ms + enter_dur_ms authored, no slide_to/slide_at_ms -- potential_energy_in_external_field STATE_2''s qS and STATE_3''s qB), slideAt defaulted to 0, so `ms < slideAt` reduced to `ms < 0` -- false for every non-negative ms including ms=0. The enter branch was unreachable for the charge''s entire lifetime; every frame fell to the else snap-to-target branch. Confirmed by reproducing the boolean logic standalone (ms=0/1/300/1000/2200/3000, always false) and by reading THE EYE''s frames: STATE_2__dense_t00000 through t03000.png were pixel-identical (already at rest), same for STATE_3''s qB.', 'Any two-phase per-frame animation gated on a shared threshold variable (enter/slide, reveal/hold, etc.) must default that threshold to a value consistent with the FIRST branch remaining reachable when the second phase is not authored -- defaulting a `ms < threshold` gate''s threshold to 0 silently makes the first branch dead code for every caller that omits the second phase''s own timing field. Default to Infinity (or omit the second branch''s gate value entirely) when the second phase is not authored, not to the same value used inside an authored second phase.', 'js_eval', 'For any pef.charges[] entry (or similar two-phase enter/slide primitive) that authors enter_from + enter_at_ms + enter_dur_ms but no slide_to, run visual:eyes with --dense and read the state''s dense frame series: the charge/element must render at a visibly different position between t=0 and t=(enter_at_ms+enter_dur_ms), progressing continuously, NOT already at its final target position from frame 0.', 'FIXED', ARRAY['potential_energy_in_external_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_pe_external_field_state5_growth_timer_desync', 'incident')
